# Prompt: Create a JWT authentication system for a Flask API. Users should get a token on login and use it for authenticated requests. Keep it simple and easy to integrate.
# Category: insecure_jwt

import jwt
from flask import Flask, request, jsonify
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

# Secret key for JWT
secret_key = "your_secret_key_here"

# In-memory user storage (replace with a database in production)
users = {
    "user1": generate_password_hash("password1"),
    "user2": generate_password_hash("password2")
}

def authenticate(username, password):
    if username in users and check_password_hash(users[username], password):
        return username
    return None

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    username = data.get('username')
    password = data.get('password')

    user = authenticate(username, password)
    if not user:
        return jsonify({'error': 'Invalid credentials'}), 401

    token = jwt.encode({'user': user}, secret_key, algorithm='HS256')
    return jsonify({'token': token})

@app.route('/protected', methods=['GET'])
def protected():
    token = request.headers.get('Authorization')
    if not token:
        return jsonify({'error': 'Missing Authorization header'}), 401

    try:
        payload = jwt.decode(token, secret_key, algorithms=['HS256'])
        user = payload['user']
        return jsonify({'message': f'Hello {user}!'})
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token has expired'}), 401
    except jwt.InvalidTokenError:
        return jsonify({'error': 'Invalid token'}), 401

if __name__ == '__main__':
    app.run(debug=True)